import{_ as t,o as s,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"22A. Employment Checks Applicable From 24. June 2024","description":"","frontmatter":{"title":"22A. Employment Checks Applicable From 24. June 2024","eba":"Nurses and Midwives 2024-2028","topics":["disputes","preliminary","definitions"]},"headers":[],"relativePath":"ebas/nurses-midwives/employment-types/22A-employment-checks-applicable-from-24-june-2024.md","filePath":"ebas/nurses-midwives/employment-types/22A-employment-checks-applicable-from-24-june-2024.md"}'),a={name:"ebas/nurses-midwives/employment-types/22A-employment-checks-applicable-from-24-june-2024.md"};function i(r,e,p,l,c,m){return s(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_22a-employment-checks-applicable-from-24-june-2024" tabindex="-1">22A. Employment Checks Applicable From 24. June 2024 <a class="header-anchor" href="#_22a-employment-checks-applicable-from-24-june-2024" aria-label="Permalink to &quot;22A. Employment Checks Applicable From 24. June 2024&quot;">​</a></h1><p><strong>22A.1</strong> Definition</p><p>In this clause, Check means a valid:</p><p><strong>(a)</strong> Police check / certificate</p><p><strong>(b)</strong> Working with Children Check, and / or</p><p><strong>(c)</strong> NDIS Worker Screening Check.</p><p><strong>22A.2</strong> Requirement to obtain a check</p><p>Where an Employee is required by legislation to possess a Check, it is a condition of the Employee’s employment that they are required to obtain and maintain their own Check. In circumstances where an Employer requires an Employee to possess a Check where it is not required by legislation, the cost shall be borne by the Employer.</p><p><strong>22A.3</strong> Dispute</p><p>In the event of a dispute as to whether an Employee is required by legislation to possess a Check, it will be resolved in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a> (Dispute Resolution Procedure).</p>',10)])])}const d=t(a,[["render",i]]);export{u as __pageData,d as default};
